#include <stdio.h>
#include <string.h>
#define MAX 1000001
int dp[MAX];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[1000001];
        int M;
        scanf("%s %d", A, &M);
        int n = strlen(A);
        int count = 0;
        for (int i = 0; i < n; i++) {
            int num = 0;
            for (int j = 0; j < n; j++) {
                if (j != i) {
                    num = num * 10 + (A[j] - '0');
                }
            }
            int rem = num % M;
            int flag = 0;
            for (int j = 0; j < n; j++) {
                if (j != i) {
                    int digit = A[j] - '0';
                    if ((rem * 10 + digit) % M == 0) {
                        flag = 1;
                        break;
                    }
                    rem = (rem * 10 + digit) % M;
                }
            }
            if (flag) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

